import{_ as o,o as a,c as r,ag as n}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"reference/changelog.md","filePath":"reference/changelog.md","lastUpdated":null}'),t={name:"reference/changelog.md"};function i(l,e,c,d,s,g){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="v2-0-0" tabindex="-1">v2.0.0 <a class="header-anchor" href="#v2-0-0" aria-label="Permalink to &quot;v2.0.0&quot;">​</a></h2><h3 id="breaking-changes" tabindex="-1">Breaking changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking changes&quot;">​</a></h3><ul><li><strong>ESLint removed</strong> — generated projects now use <a href="https://biomejs.dev" target="_blank" rel="noreferrer">Biome</a> for both linting and formatting. Do not add <code>.eslintrc</code> files to generated projects.</li><li><strong>Node 20 minimum</strong> — Node 16 and 18 are no longer supported. Node 24 is recommended.</li><li><strong>pnpm 10.30.1 required</strong> — the <code>packageManager</code> field in generated <code>package.json</code> files is locked to <code>pnpm@10.30.1</code>.</li></ul><h3 id="new-features" tabindex="-1">New features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li>Biome replaces ESLint: faster, zero-config, single tool for lint and format</li><li><code>noConsole: error</code> enforced at build time — prevents accidental <code>console.log</code> in production bundles</li><li><code>watchFor()</code> added to <code>lib/framework.js</code> — MutationObserver-based alternative to <code>waitFor</code> with auto-disconnect timeout</li><li>30+ Samsung markets available for E2E test configuration</li><li>Multi-country market groups (SEBN, SENA, SEIB) for multi-locale E2E parametrisation</li><li>Local search in documentation (<code>search.provider: &#39;local&#39;</code>)</li></ul><h3 id="migration-from-v1" tabindex="-1">Migration from v1 <a class="header-anchor" href="#migration-from-v1" aria-label="Permalink to &quot;Migration from v1&quot;">​</a></h3><p>For step-by-step instructions including before/after code examples, see the <a href="/reference/migration.html">Migration Guide</a>.</p><p><strong>Summary:</strong></p><ol><li>Remove <code>node_modules/</code> and any <code>.eslintrc*</code> files</li><li>Add <code>biome.json</code> (copy from a freshly scaffolded project)</li><li>Update <code>package.json</code> scripts: replace <code>eslint</code> commands with <code>biome check src</code></li><li>Run <code>nvm use 24</code> and reinstall: <code>pnpm install</code></li><li>Run <code>pnpm lint</code> and fix any Biome violations</li></ol>',10)])])}const f=o(t,[["render",i]]);export{h as __pageData,f as default};
